// Análise avançada de perfil para personalização
const member = $input.first().json;

// Determinar personas baseadas em múltiplos fatores
function determinePersona(member) {
  const { faixa_etaria, modalidade_preferida, score_engajamento, prefere_promocao, plano_premium, inadimplente } = member;

  // Persona 1: Fitness Enthusiast (Alto engajamento, premium)
  if (score_engajamento > 70 && plano_premium) {
    return {
      persona: 'fitness_enthusiast',
      tom: 'motivacional_técnico',
      foco: 'performance_evolução',
      emoji_style: '🏆💪🔥',
      urgencia: 'baixa'
    };
  }

  // Persona 2: Bargain Hunter (Sensível a preço)
  if (prefere_promocao || inadimplente) {
    return {
      persona: 'bargain_hunter', 
      tom: 'promocional_benefícios',
      foco: 'valor_economia',
      emoji_style: '💰🎁✅',
      urgencia: 'alta'
    };
  }

  // Persona 3: Busy Professional (Baixo engajamento, falta tempo)
  if (faixa_etaria === 'adulto' && score_engajamento < 40) {
    return {
      persona: 'busy_professional',
      tom: 'prático_flexível', 
      foco: 'conveniência_tempo',
      emoji_style: '⏰🎯💼',
      urgencia: 'média'
    };
  }

  // Persona 4: Health Seeker (Sênior ou foco saúde)
  if (faixa_etaria === 'senior' || modalidade_preferida.includes('funcional')) {
    return {
      persona: 'health_seeker',
      tom: 'cuidado_bem_estar',
      foco: 'saúde_qualidade_vida', 
      emoji_style: '🧘‍♀️💚🌟',
      urgencia: 'baixa'
    };
  }

  // Persona 5: Social Butterfly (Jovem, atividades grupo)
  if (faixa_etaria === 'jovem' && modalidade_preferida.includes('grupo')) {
    return {
      persona: 'social_butterfly',
      tom: 'energia_comunidade',
      foco: 'diversão_social',
      emoji_style: '🎉👥💃', 
      urgencia: 'média'
    };
  }

  // Default: Casual Member
  return {
    persona: 'casual_member',
    tom: 'amigável_simples',
    foco: 'retorno_básico',
    emoji_style: '😊🏋️👍',
    urgencia: 'média'
  };
}

// Gerar mensagem personalizada
function generatePersonalizedMessage(member, persona, campaignType) {
  const firstName = member.primeiro_nome || member.nome_completo.split(' ')[0];
  const { tom, foco, emoji_style } = persona;

  const templates = {
    fitness_enthusiast: {
      QUENTE: `${firstName}, seus ganhos estão te esperando! 🏆 Que tal quebrarmos seu PR essa semana? Seu treino personalizado já está pronto! 💪🔥`,
      MORNO: `${firstName}, seu corpo sente falta do desafio! 🔥 Programa especial de retorno: avaliação biomecânica + treino periodizado. Vamos evoluir! 🏆💪`,
      FRIO: `${firstName}, é hora do COMEBACK! 🚀 Treino de retorno gradual + acompanhamento técnico individual. Seus músculos lembram! 💪🎯`
    },
    bargain_hunter: {
      QUENTE: `${firstName}, OFERTA RELÂMPAGO! ⚡ 50% OFF na volta + kit academia GRÁTIS! Só hoje! Responda JÁ! 💰🎁`,
      MORNO: `${firstName}, 🚨 PROMOÇÃO EXCLUSIVA: 3 meses pelo preço de 1 + matrícula grátis! Economize R$ 270! Válido 48h! 💰✅`,
      FRIO: `${firstName}, ÚLTIMA CHANCE! 🔥 70% OFF + sem taxa de adesão + 1 mês grátis! Essa é THE oferta do ano! 🎁💰⏰`
    },
    busy_professional: {
      QUENTE: `${firstName}, treino EXPRESS em 30min! ⏰ Horários flexíveis 6h-22h. Malhe no seu tempo, sem stress! 🎯💼`,
      MORNO: `${firstName}, academia que SE ADAPTA a você! ⏰ App próprio + treinos 24h + planos flexíveis. Produtividade em 1° lugar! 💼🎯`,
      FRIO: `${firstName}, SOLUÇÃO para sua agenda! 🎯 Treino home + academia quando quiser + app premium. Só 30min/dia! ⏰💪`
    },
    health_seeker: {
      QUENTE: `${firstName}, cuide de si com carinho! 💚 Atividades leves, acompanhamento profissional e ambiente acolhedor te esperam! 🧘‍♀️🌟`,
      MORNO: `${firstName}, seu bem-estar é prioridade! 🌟 Programa sênior: fisioterapia + pilates + musculação adaptada. Saúde em 1° lugar! 💚🧘‍♀️`,
      FRIO: `${firstName}, movimento é vida! 🌟 Volta gradual com foco na sua saúde: exercícios terapêuticos + acompanhamento médico! 💚🧘‍♀️`
    },
    social_butterfly: {
      QUENTE: `${firstName}, a galera tá com saudade! 🎉 Aulas em grupo, eventos exclusivos e aquela energia contagiante! Bora? 👥💃`,
      MORNO: `${firstName}, NOVIDADE! 🎉 Aulas temáticas + challenges em grupo + eventos sociais! A academia virou um point! 👥💃🔥`,
      FRIO: `${firstName}, a comunidade Full Force te chama! 🎉 Volta com tudo: grupo VIP + eventos exclusivos + amizades pra vida! 👥💃🌟`
    },
    casual_member: {
      QUENTE: `Oi ${firstName}! 😊 Que tal voltarmos aos poucos? Treino personalizado e todo apoio que você precisa! 🏋️👍`,
      MORNO: `${firstName}, preparamos um plano especial para você! 😊 Avaliação + programa personalizado + acompanhamento. Vamos juntos! 🏋️💪`,
      FRIO: `${firstName}, nova chance de cuidar de você! 😊 Volta sem pressa: plano flexível + suporte total da nossa equipe! 🏋️👍🌟`
    }
  };

  return templates[persona.persona]?.[campaignType] || templates.casual_member[campaignType];
}

// Processar membro
const persona = determinePersona(member);
const campaignType = member.classificacao_reativacao || 'MORNO';
const personalizedMessage = generatePersonalizedMessage(member, persona, campaignType);

// Determinar melhor horário de envio
const bestTimeToSend = (() => {
  const horarioPreferido = member.horario_preferido;
  const currentHour = new Date().getHours();

  if (horarioPreferido === 'manhã' && currentHour < 10) return 'immediate';
  if (horarioPreferido === 'tarde' && currentHour >= 12 && currentHour < 18) return 'immediate';
  if (horarioPreferido === 'noite' && currentHour >= 18) return 'immediate';

  // Agendar para horário preferido
  return horarioPreferido === 'manhã' ? '08:00' : 
         horarioPreferido === 'tarde' ? '14:00' : '19:00';
})();

return [{
  json: {
    ...member,
    persona: persona,
    personalizedMessage: personalizedMessage,
    bestTimeToSend: bestTimeToSend,
    campaignType: campaignType,
    processingTimestamp: new Date().toISOString(),

    // Dados para tracking
    personalization: {
      persona_detected: persona.persona,
      tone_used: persona.tom,
      focus_area: persona.foco,
      urgency_level: persona.urgencia,
      engagement_score: member.score_engajamento
    }
  }
}];
